import requests
import json
import sys

url = 'https://api.wandb.ai/graphql'

run_ids = ["ma1txjj5", "qdm5cwl6", "9mmkwskw", "ihdboejo", "prwodjfw", "it75fa5k", "3j96ix1q", "8i67e0vf"]

# Get history via GraphQL - use sampledHistory with specs
# We need to get val-core metrics at each step
all_results = {}

for run_id in run_ids:
    # Get history lines with val-core metrics
    # Try using the historyLineCount to paginate
    query = {
        "query": """{
  project(entityName: "mbzuai-llm", projectName: "Guru") {
    runs(first: 1, filters: "{\"name\": \"""" + run_id + """\"}") {
      edges {
        node {
          name
          displayName
          state
          history(first: 2000) {
            edges {
              node {
                event
                step
                data
              }
            }
          }
        }
      }
    }
  }
}"""
    }
    r = requests.post(url, json=query, timeout=60)
    data = r.json()

    if "errors" in data:
        print(f"Error for {run_id}: {data['errors'][0]['message']}", file=sys.stderr)
        continue

    edges = data["data"]["project"]["runs"]["edges"]
    if not edges:
        print(f"No data for {run_id}", file=sys.stderr)
        continue

    node = edges[0]["node"]
    history_edges = node["history"]["edges"]

    print(f"\n=== {run_id} | {node['displayName']} ===", flush=True)
    print(f"  History lines: {len(history_edges)}", flush=True)

    # Extract val-core metrics per step
    step_data = []
    for he in history_edges:
        hn = he["node"]
        step = hn.get("step", 0)
        try:
            metrics = json.loads(hn.get("data", "{}"))
        except:
            metrics = {}

        val_core = {}
        for k, v in metrics.items():
            if k.startswith("val-core/") and isinstance(v, (int, float)):
                val_core[k] = v

        if val_core:
            step_data.append({"step": step, "metrics": val_core})

    if step_data:
        # Find the last step with val-core data
        last = step_data[-1]
        print(f"  Last step with val-core: {last['step']}", flush=True)
        for k in sorted(last["metrics"].keys()):
            print(f"    {k}: {last['metrics'][k]}", flush=True)
    else:
        print("  No val-core metrics in history", flush=True)

    all_results[run_id] = step_data

with open("tmp/history_val_core.json", "w") as f:
    json.dump(all_results, f, indent=2)

print("\nDone. Saved to tmp/history_val_core.json", flush=True)

