import json
from collections import defaultdict

with open("tmp/all_history.json") as f:
    data = json.load(f)

# Group runs by displayName (treat same-name runs as one)
run_groups = defaultdict(list)
for run_id, info in data.items():
    run_groups[info["displayName"]].append({
        "run_id": run_id,
        "state": info["state"],
        "step_data": info["step_data"]
    })

# For each group, combine all step data
# Define the key metrics (mean@1 for most, mean@k for aime/amc)
# The benchmarks are:
# codegen__humaneval, codegen__livecodebench, codegen__mbpp
# logic__graph_logical_dataset, logic__ordering_puzzle_dataset, logic__zebra_puzzle_dataset
# math__aime_repeated_8x (mean@8), math__amc_repeated_4x (mean@4), math__math
# simulation__arcagi1, simulation__codeio
# stem__gpqa, stem__supergpqa
# table__hitab, table__multihier

# For 7B runs, the key is best@1 instead of mean@1
# Let's identify all benchmark keys

all_benchmarks = set()
for display_name, runs in run_groups.items():
    for run in runs:
        for sd in run["step_data"]:
            for k in sd["metrics"]:
                # Extract benchmark part
                parts = k.split("/")
                if len(parts) >= 4 and "acc/" in k:
                    all_benchmarks.add(k)

print("All benchmark metric keys found:")
for b in sorted(all_benchmarks):
    print(f"  {b}")

# For each group, for each benchmark, find the highest score across all steps of all sub-runs
# Also find the step at which it occurs
print("\n" + "="*80)

results = {}
for display_name, runs in run_groups.items():
    print(f"\n=== {display_name} ({len(runs)} sub-runs) ===")

    # Combine all step data from all sub-runs
    all_steps = []
    for run in runs:
        for sd in run["step_data"]:
            all_steps.append(sd)

    # Sort by step
    all_steps.sort(key=lambda x: x["step"])

    # For each benchmark key, find max value and the step
    best_per_benchmark = {}
    for sd in all_steps:
        for k, v in sd["metrics"].items():
            if "/std" in k:
                continue
            if k not in best_per_benchmark or v > best_per_benchmark[k]["value"]:
                best_per_benchmark[k] = {"value": v, "step": sd["step"]}

    results[display_name] = best_per_benchmark

    for k in sorted(best_per_benchmark.keys()):
        bv = best_per_benchmark[k]
        print(f"  {k}: {bv['value']:.6f} @ step {bv['step']}")

# Now find the best step per run group (step with highest average of available metrics)
print("\n" + "="*80)
print("BEST STEP ANALYSIS")
print("="*80)

for display_name, runs in run_groups.items():
    print(f"\n=== {display_name} ===")

    all_steps = []
    for run in runs:
        for sd in run["step_data"]:
            all_steps.append(sd)

    all_steps.sort(key=lambda x: x["step"])

    # For each step, compute average of available val-core metrics (excluding std)
    step_avgs = []
    for sd in all_steps:
        vals = {k: v for k, v in sd["metrics"].items() if "/std" not in k and isinstance(v, (int, float))}
        if vals:
            avg = sum(vals.values()) / len(vals)
            step_avgs.append({"step": sd["step"], "avg": avg, "n_metrics": len(vals), "metrics": vals})

    if step_avgs:
        # Find step with highest average
        best = max(step_avgs, key=lambda x: x["avg"])
        print(f"  Best step: {best['step']} (avg: {best['avg']:.6f}, n_metrics: {best['n_metrics']})")
        print(f"  All steps avg range: {min(s['avg'] for s in step_avgs):.4f} - {max(s['avg'] for s in step_avgs):.4f}")

        # Show top 5 steps
        top5 = sorted(step_avgs, key=lambda x: x["avg"], reverse=True)[:5]
        for t in top5:
            print(f"    Step {t['step']}: avg={t['avg']:.6f} ({t['n_metrics']} metrics)")
    else:
        print("  No step data available")

with open("tmp/best_per_benchmark.json", "w") as f:
    json.dump(results, f, indent=2)
